SELECT "t3"."$f4", "t3"."$f10", "t3"."$f20", "t3"."$f30"
FROM (SELECT SUBSTRING("REASON"."R_REASON_DESC", 1, 20) AS "$f4", AVG("WEB_SALES"."WS_QUANTITY") AS "$f10", AVG("WEB_RETURNS"."WR_REFUNDED_CASH") AS "$f20", AVG("WEB_RETURNS"."WR_FEE") AS "$f30"
FROM "tpcds"."WEB_SALES",
"tpcds"."WEB_RETURNS",
"tpcds"."WEB_PAGE",
"tpcds"."CUSTOMER_DEMOGRAPHICS",
"tpcds"."CUSTOMER_DEMOGRAPHICS" AS "CUSTOMER_DEMOGRAPHICS0",
"tpcds"."CUSTOMER_ADDRESS",
"tpcds"."DATE_DIM",
"tpcds"."REASON"
WHERE "WEB_SALES"."WS_WEB_PAGE_SK" = "WEB_PAGE"."WP_WEB_PAGE_SK" AND "WEB_SALES"."WS_ITEM_SK" = "WEB_RETURNS"."WR_ITEM_SK" AND ("WEB_SALES"."WS_ORDER_NUMBER" = "WEB_RETURNS"."WR_ORDER_NUMBER" AND ("WEB_SALES"."WS_SOLD_DATE_SK" = "DATE_DIM"."D_DATE_SK" AND "DATE_DIM"."D_YEAR" = 1998)) AND ("CUSTOMER_DEMOGRAPHICS"."CD_DEMO_SK" = "WEB_RETURNS"."WR_REFUNDED_CDEMO_SK" AND ("CUSTOMER_DEMOGRAPHICS0"."CD_DEMO_SK" = "WEB_RETURNS"."WR_RETURNING_CDEMO_SK" AND "CUSTOMER_ADDRESS"."CA_ADDRESS_SK" = "WEB_RETURNS"."WR_REFUNDED_ADDR_SK") AND ("REASON"."R_REASON_SK" = "WEB_RETURNS"."WR_REASON_SK" AND (("CUSTOMER_DEMOGRAPHICS"."CD_MARITAL_STATUS" = '[MS.1]' AND "CUSTOMER_DEMOGRAPHICS"."CD_MARITAL_STATUS" = "CUSTOMER_DEMOGRAPHICS0"."CD_MARITAL_STATUS" AND "CUSTOMER_DEMOGRAPHICS"."CD_EDUCATION_STATUS" = '[ES.1]' AND "CUSTOMER_DEMOGRAPHICS"."CD_EDUCATION_STATUS" = "CUSTOMER_DEMOGRAPHICS0"."CD_EDUCATION_STATUS" AND ("WEB_SALES"."WS_SALES_PRICE" >= 100.00 AND "WEB_SALES"."WS_SALES_PRICE" <= 150.00) OR "CUSTOMER_DEMOGRAPHICS"."CD_MARITAL_STATUS" = '[MS.2]' AND "CUSTOMER_DEMOGRAPHICS"."CD_MARITAL_STATUS" = "CUSTOMER_DEMOGRAPHICS0"."CD_MARITAL_STATUS" AND "CUSTOMER_DEMOGRAPHICS"."CD_EDUCATION_STATUS" = '[ES.2]' AND "CUSTOMER_DEMOGRAPHICS"."CD_EDUCATION_STATUS" = "CUSTOMER_DEMOGRAPHICS0"."CD_EDUCATION_STATUS" AND ("WEB_SALES"."WS_SALES_PRICE" >= 50.00 AND "WEB_SALES"."WS_SALES_PRICE" <= 100.00) OR "CUSTOMER_DEMOGRAPHICS"."CD_MARITAL_STATUS" = '[MS.3]' AND "CUSTOMER_DEMOGRAPHICS"."CD_MARITAL_STATUS" = "CUSTOMER_DEMOGRAPHICS0"."CD_MARITAL_STATUS" AND "CUSTOMER_DEMOGRAPHICS"."CD_EDUCATION_STATUS" = '[ES.3]' AND "CUSTOMER_DEMOGRAPHICS"."CD_EDUCATION_STATUS" = "CUSTOMER_DEMOGRAPHICS0"."CD_EDUCATION_STATUS" AND ("WEB_SALES"."WS_SALES_PRICE" >= 150.00 AND "WEB_SALES"."WS_SALES_PRICE" <= 200.00)) AND ("CUSTOMER_ADDRESS"."CA_COUNTRY" = 'United States' AND CAST("CUSTOMER_ADDRESS"."CA_STATE" AS VARCHAR(10)) IN ('[STATE.1]', '[STATE.2]', '[STATE.3 ]') AND (CAST("WEB_SALES"."WS_NET_PROFIT" AS DECIMAL(12, 2)) >= 100.00 AND CAST("WEB_SALES"."WS_NET_PROFIT" AS DECIMAL(12, 2)) <= 200.00) OR "CUSTOMER_ADDRESS"."CA_COUNTRY" = 'United States' AND CAST("CUSTOMER_ADDRESS"."CA_STATE" AS VARCHAR(9)) IN ('[STATE.4]', '[STATE.5]', '[STATE.6]') AND (CAST("WEB_SALES"."WS_NET_PROFIT" AS DECIMAL(12, 2)) >= 150.00 AND CAST("WEB_SALES"."WS_NET_PROFIT" AS DECIMAL(12, 2)) <= 300.00) OR "CUSTOMER_ADDRESS"."CA_COUNTRY" = 'United States' AND CAST("CUSTOMER_ADDRESS"."CA_STATE" AS VARCHAR(9)) IN ('[STATE.7]', '[STATE.8]', '[STATE.9]') AND (CAST("WEB_SALES"."WS_NET_PROFIT" AS DECIMAL(12, 2)) >= 50.00 AND CAST("WEB_SALES"."WS_NET_PROFIT" AS DECIMAL(12, 2)) <= 250.00)))))
GROUP BY "REASON"."R_REASON_DESC"
ORDER BY 1, 2, 3, 4
FETCH NEXT 100 ROWS ONLY) AS "t3"
